import React, { useState } from "react";
import { loginUser } from "./api/auth";
import "./Login.css";

export default function Login() {
  const [loginId, setLoginId] = useState("");
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);

    try {
      const res = await loginUser(loginId, password);

      if (res.data?.success) {
        const emp = res.data.employee;

        // ⭐ Store correct backend fields
        localStorage.setItem("employee_id", emp.employee_id);
        localStorage.setItem("name", emp.name);
        localStorage.setItem("department", emp.department);

        window.location.href = "/home";
      } else {
        alert("Invalid Employee ID or Password");
      }
    } catch (err) {
      alert("Server Error — check backend.");
    }

    setBusy(false);
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <img
          src="/logo.png"
          alt="PRASA Logo"
          style={{
            height: 80,
            width: 80,
            objectFit: "contain",
            background: "#fff",
            borderRadius: 12,
            marginBottom: 12,
            boxShadow: "0 3px 12px rgba(0,0,0,0.12)"
          }}
        />

        <h2 className="title">Employee Login</h2>

        <form onSubmit={submit}>
          <input
            className="input-box"
            placeholder="Employee ID / Login ID"
            value={loginId}
            onChange={(e) => setLoginId(e.target.value)}
          />

          <input
            className="input-box"
            placeholder="Password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <button className="btn-login" type="submit" disabled={busy}>
            {busy ? "Logging In..." : "Login"}
          </button>
        </form>
      </div>
    </div>
  );
}
